107	async function create() {
108	  if (!gf.value.taskName?.trim()) { toast('请先填写任务名', 'warning'); step.value = 2; return }
109	  const isAuto = tab.value === 'auto'
110	  const fmt = gf.value.outputFormat.trim()
111	  const fullPrompt = fmt ? `${gf.value.prompt}\n\n${fmt}` : gf.value.prompt
112	  const payload = {
113	    type: tab.value, name: gf.value.taskName,
114	    targetAccount: gf.value.targetAccount,
115	    accountId: gf.value.accountId,
116	    modelId: Number(gf.value.modelId || mock.defaultAIModelId),
117	    schedule: isAuto ? `每天 ${gf.value.runTime}` : '-',
118	    sourceCount: isAuto ? Number(gf.value.maxArticles || 5) : selIds.value.size,
119	    sourceArticles: isAuto ? [] : [...selIds.value],
120	    prompt: fullPrompt, outputFormat: fmt,
121	    nextRun: isAuto ? `${gf.value.runDate} ${gf.value.runTime}` : '-',
122	    excludeUsed: isAuto ? gf.value.excludeUsed : false,
123	    generateImages: gf.value.generateImages,
124	    generateCover: gf.value.generateCover,
125	    imageCount: Number(gf.value.imageCount || 2),
126	    imageModelId: gf.value.imageModelId ? Number(gf.value.imageModelId) : null,
127	    status: '待执行'
128	  }
129	  try {
130	    await apiPost('/generation/tasks', payload)
131	    await loadServerBootstrap()
132	  } catch {
133	    mock.generationTasks.unshift({ id: Date.now(), ...payload })
134	  }
135	  showModal.value = false
136	  toast(isAuto ? '\u5df2\u4fdd\u5b58\u81ea\u52a8\u4efb\u52a1' : '\u5df2\u521b\u5efa\u624b\u52a8\u4efb\u52a1', 'success')
137	}
