139	async function run(id) {
140	  const task = mock.generationTasks.find(x => x.id === id)
141	  if (!task) return
142	  if (isJoinLocked(task.status)) {
143	    toast('任务已加入队列', 'warning')
144	    return
145	  }
146	  const prevStatus = task.status || '待执行'
147	  task.status = '排队中'
148	  try { await apiPut(`/generationTasks/${id}`, { status: '排队中' }) } catch (e) { console.warn(e) }
149	  try {
150	    const res = await apiPost('/tasks/enqueue', { ...task, generationTaskId: id, generationType: task.type, type: 'generate' })
151	    const queueTask = res?.task
152	    if (queueTask) {
153	      const idx = mock.queue.findIndex(x => x.id === queueTask.id)
154	      if (idx === -1) mock.queue.unshift(queueTask)
155	      else mock.queue[idx] = queueTask
156	    }
157	  } catch (err) {
158	    task.status = prevStatus
159	    try { await apiPut(`/generationTasks/${id}`, { status: prevStatus }) } catch (e) { console.warn(e) }
160	    toast(err.message || '生成任务入队失败', 'error')
161	  }
162	}
