164	async function del(id) {
165	  if (!confirm('确定删除这个生成任务吗？')) return
166	  try { await apiDelete(`/generationTasks/${id}`); await loadServerBootstrap() }
167	  catch { mock.generationTasks.splice(mock.generationTasks.findIndex(t => t.id === id), 1) }
168	}
